3_real_world_example.code:
const user = {
  name: 'Alice',
  greet() {
    return `Hello, I am ${this.name}`;
  }
};

// Method call: 'this' = user 
console.log(user.greet()); // 'Hello, I am Alice'

// Detached: 'this' is no longer 'user' 
const detached = user.greet;
console.log(detached()); // 'Hello, I am undefined' (or throws in strict mode)

// Fix 1: bind permanently
const bound = user.greet.bind(user);
console.log(bound()); // 'Hello, I am Alice' 

// Fix 2: arrow function method alternative
const timer = {
  label: 'Timer',
  start() {
    setTimeout(() => {
      console.log(this.label); // 'Timer'  — arrow captures outer 'this'
    }, 100);
  }
};
timer.start();

