'use strict';

function checkThis() {
  console.log(this); // undefined (strict) vs window/global (non-strict)
}

checkThis();

// Guard pattern: explicitly check for undefined this
function safeMethod() {
  if (this === undefined) {
    throw new Error('Must be called as a method, not a standalone function');
  }
  return this.name;
}
